var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"아! 왔군. 마리아 안토노프 중장. 막 리허설이 시작되려던 참일세.","JPN":"あ！来たか、マリア・アントノフ中将。たった今、リハーサルが始まったところだ。","ENG":"Ah! So you've come, Lieutenant General Maria Antonov. The rehearsal is just about to begin.","TWN":"啊！妳來了啊，瑪麗亞·安東諾夫中將。彩排正好要開始了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"반갑습니다, 장관님. 프로젝트의 공개 참관을 허락해주셔서 고맙군요.","JPN":"お会いできて光栄です、長官。プロジェクトの公開演習をご承諾いただき、ありがとうございます。","ENG":"Very nice to see you, Mr. Secretary. Thank you for allowing me to sit in on the open viewing of the project.","TWN":"見到您很高興，長官。謝謝您允許我參觀這個計畫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"당연한 걸 고마워하지 말게. 오히려 소파에 앉아 TV로 편하게 봐도 됐을 텐데 말이야.","JPN":"当然のことだからお礼は結構だ。むしろソファーに座ってテレビで見てるほうが楽だったと思うがな。","ENG":"No need to thank me for doing what should be done. If anything, you could've just watched from the comfort of your own television back home.","TWN":"不用謝，這是我應該做的。反倒是中將，明明妳可以舒服地坐在沙發上用電視觀看的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런데, 시연 방식이 조금 독특하더군요.","JPN":"ところで、演習の方法が少し独特ですね。","ENG":"By the way, the demonstration methodology seemed rather unusual.","TWN":"不過，這個表演方式似乎有些獨特呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"특공부대원들과 10대 1 근접전투라니. 이런 게 정말로 의미가 있는 시연입니까?","JPN":"特攻部隊員たちと10対1の近接戦闘とは。これは本当に有意味な試演なのでしょうか？","ENG":"A 10-on-1 melee with special forces troops? Does this sort of thing really bear much meaning in this demonstration?","TWN":"居然與特種部隊隊員進行10對1的近身格鬥。這種表演真的有意義嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하하, 공개 프로젝트인 만큼 모든 매스컴의 주목을 받고 있으니 말이지.","JPN":"はは、公開プロジェクトということもあって、全マスコミから注目されているからな。","ENG":"Hah hah, given that it's a public project, we've got the attention of all the media.","TWN":"哈哈，既然這是公開的計畫，就一定要足夠吸引媒體的眼球啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"이 프로젝트의 중요성을 과시하기에 대련만큼 직관적인 수단도 없다네.","JPN":"このプロジェクトの重要性を見せつけるのに、立ち合い稽古ほど効果的なものもない。","ENG":"There's nothing as effective as sparring to demonstrate the importance of this project.","TWN":"要展現這個計畫重要性，對練就是最直觀的手段了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"우리가 실질적으로 추진하는 프로젝트는 유능한 군인을 키워내는 일이지만......","JPN":"我々が実際に推進しているプロジェクトは、有能な軍人を育てることだが……","ENG":"Although what we're really after is to foster capable service members...","TWN":"雖然我們的計畫實質上是培養優秀的軍人……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그런 내용을 단상 위에서 실컷 떠들어봤자 국민의 지지를 받긴 힘들거든.","JPN":"そんな内容を壇上に立って喋っても、国民の支持を得られにくいからな。","ENG":"We can't win the support of the public on that talking point, no matter how long we spend giving a speech on the pedestal.","TWN":"但不管再怎麼吹噓這個計畫有多重要，大概也很難得到國民的支持。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"프로젝트의 주인공이 수적 불리의 상황을 멋지게 극복해내는 연출만큼 정치적 편파를 떠나 만인의 지지를 받기 좋은 장치도 없지.","JPN":"プロジェクトの主人公が、数の上での不利な状況を見事に乗り越える演出こそ、\\n政治的偏見によらず万人の支持を得るのにちょうどいい措置だ。","ENG":"An outnumbered protagonist overcoming his struggle... There's no method more effective than this plot device, regardless of the political leanings of the audience.","TWN":"像電影主角那樣帥氣克服各種難關，以一己之力打敗數量眾多的敵人……要讓人們拋開政治偏見支持我們，這是最好的方法了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"잘 차려 입은 저 친구가 프로젝트의 주인공입니까?","JPN":"ドレスアップした彼がプロジェクトの主人公ですか？","ENG":"So is that sharply dressed fellow the protagonist of the project?","TWN":"那位衣冠楚楚的朋友就是這個計畫的主角嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그렇다네. 이름은 카일 웡. 이번 프로젝트의 대표주자라고 할 수 있는 최고 엘리트 훈련병이지.","JPN":"そうだ。彼の名前はカイル・ウォン。今回のプロジェクトのメインメンバーとも言える超エリート訓練兵だ。","ENG":"That's right. His name is Kyle Wong. He's an elite trainee. We could virtually dub him as the best of the best in this project.","TWN":"沒錯。他叫凱爾。他可以說是這次計畫的主力，是非常優秀的精英訓練兵。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"적당한 사복이면 괜찮다고 했는데, 자네가 참관할 거라 귀띔했더니 기어이 저 복장을 고르더군.","JPN":"普段通りの私服で構わないと言ってたが、君が参観することを耳打ちしてやったら、あの服を纏ったわけだ。","ENG":"I told him he's free to wear anything, but he insisted on wearing that when I let him know you'd be watching.","TWN":"雖然我說穿合適的衣服就行，但他聽說你會參觀，所以選了那套服裝。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"음? 저 친구가 저를 알고 있답니까?","JPN":"うん？　彼が私のことを知っていたんですか？","ENG":"Huh? He knows about me?","TWN":"嗯？那位朋友認識我嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"겸손하긴. 자넨 전쟁에서 인류를 승리로 이끈 영웅이지 않나.","JPN":"そんなに謙遜することはない。君は戦争で人類を勝利に導いた英雄じゃないか。","ENG":"No need to be so modest. You led humanity to victory in the last war. You're a hero.","TWN":"太謙虛了。妳可是帶領人類走向勝利的英雄啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"난 물론이고, 자넬 밀어내고 싶어하는 보수파 의원들조차, 자네의 업적만큼은 존중할 수 밖에 없다네.","JPN":"私はもちろん、君を落としたがる保守派の議員たちですら、君の功績だけは高く評価している。","ENG":"Even my conservative opponents who'd rather see you gone have no choice but to acknowledge your accomplishments.","TWN":"別說我了，就連那些想趕走你的保守派議員，也都很尊敬妳的成就。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"저 친구는 특히 더 그렇지.","JPN":"彼の場合は言うまでもない。","ENG":"It's even more the case with that fellow.","TWN":"那位朋友尤其如此。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"평소에도 열심히 했지만, 자네가 훈련소를 방문하는 날이면 유독 기합이 잔뜩 들어가곤 했거든.","JPN":"普段も頑張っているが、君が訓練場を訪問する日はなおさら気合が入ってたんだ。","ENG":"Although he was always hard working, he'd grow extra enthusiastic on the days you visited the training camp.","TWN":"雖然他平時就很認真，但妳訪問訓練所的日子他格外賣力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아, 그 기특한 친구라면 저도 기억이 납니다.","JPN":"あの健気な少年なら私も覚えています。","ENG":"Oh, I remember that peculiar fellow.","TWN":"啊，我想起那個奇特的小朋友了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"후후, 그 작은 꼬마가 저렇게 멋지게 성장하다니. 시간 참 빠르군요.","JPN":"ふふ、あのチビっ子があんなに立派になるとは。時間が経つのは早いですね。","ENG":"Hah hah, who knew that little kid would grow up like that? Time sure flies.","TWN":"呵呵，那時的小矮子已經成長得這麼帥氣了啊。時間過得真快啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......아아, 이런. 벌써 열 명을 모두 제압해버린 건가?","JPN":"……ああ、やれやれ。もう10人全員を制圧してしまったのか？","ENG":"Oh my. Has he taken down all 10 already?","TWN":"……哎呀，這，這麼快就打倒了10個人嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대원들을 상대하는데 20초도 걸리지 않다니. 대단하군요.","JPN":"特攻部隊員たちを相手に20秒もかからないなんて。すごいですね。","ENG":"It took him less than 20 seconds to engage the troops. Impressive.","TWN":"和隊員們交手居然連20秒都用不到，很厲害嘛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"휴우, 시연이 명분인 만큼 천천히 하라고 일러둔 게 저 정도라네.","JPN":"ふう、試演は建前で、ゆっくり進めろと言っておいたのがあの様さ。","ENG":"*Sigh* He actually took his time. We told him to slow down for the demonstration, you see.","TWN":"唉，這就是為什麼我得提醒他這是表演，慢慢來就行了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"효율 따지는 덴 누구보다 충실하지만, 정작 각본대로 연기를 하는 덴 별로 소질이 없더군.","JPN":"効率を考えることは誰よりも優れているが、台本通りに演技することには、あまり素質がなくてね。","ENG":"He's better than anyone at ensuring efficiency, but he's not a very promising actor, or good at sticking to the script.","TWN":"雖然在效率上他比任何人都要出色，但演戲上卻沒有天賦啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"유능하긴 한데, 다루기는 참 어려운 친구야.","JPN":"有能だが、扱いにくい部下ってことだ。","ENG":"In other words, he's capable yet difficult to rein in.","TWN":"他是很優秀沒錯，不過似乎有點難相處。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하하, 과연 그래 보이는군요.","JPN":"はは、なるほど。そう見えます。","ENG":"Hah hah, I can see that.","TWN":"哈哈，果然是這樣嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"전투 실력 외에도 카일은 군사 공학 분야에서도 뛰어난 두각을 보이고 있다네.","JPN":"戦闘の実力以外にも、カイルは軍事工学分野でも頭角を現しているんだ。","ENG":"In addition to his combat skills, he has demonstrated outstanding progress in military engineering.","TWN":"凱爾不僅戰鬥實力強大，在軍事工程領域也頗有建樹。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"융통성 부족한 성격 하나만 빼면 뭐 하나 부족한 게 없는 인재지.","JPN":"融通が効かない性格だけ除けば、何一つ足りない点がない人材だ。","ENG":"The only thing he's lacking is a little flexibility in his personality.","TWN":"除了缺乏變通性，他沒什麼缺點，是個優秀的人才。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"과연. 프로젝트를 대표하고 있는 최정예답군요.","JPN":"なるほど。プロジェクトを代表する最精鋭らしいですね。","ENG":"I see. I wouldn't expect any less from the most promising member of the project.","TWN":"原來如此，不愧是能代表計畫的精銳呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"뭐, 그렇다곤 해도 지금은 이론만 빠삭한 교육생일 뿐이야.","JPN":"まぁ、そうだとしても今は理論に精通するだけの教育生に過ぎないんだ。","ENG":"Yes, but he's still just a trainee for now, with nothing but theories in his head.","TWN":"不過他現在只是個學了理論知識的初學者而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"진짜 엘리트 군인으로 거듭나기 위해선 실전 데이터를 쌓는 것이 가장 중요해.","JPN":"本物のエリート軍人として生まれ変わるためには、実戦を積んでいくことが一番大事だ。","ENG":"In order to become a truly elite soldier, he'll have to accumulate data from real combat.","TWN":"要想成為一名精英軍人，最重要的還是積累實戰經驗。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그래서, 이 프로젝트의 마무리 단계이자 실전배치의 일환으로......","JPN":"このプロジェクトも仕上げの段階に入ってきたし、実戦配置の一環で……","ENG":"So as the final step of the project and a way to segue into active duty...","TWN":"所以，這既是計畫的收尾，也是實戰佈局的一部分……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"저 친구를 델타세븐에 편입시키려고 하는데 어떻게 생각하나?","JPN":"彼をデルタセブンに編入させたいと思っているが、どうかな？","ENG":"I was thinking of assigning him to Delta Seven. What do you think?","TWN":"我想把那位朋友編入第七三角洲部隊，妳覺得怎麼樣？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"호오......","JPN":"ほぉ……","ENG":"Oh...","TWN":"哦……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저야 마다할 이유가 없지요.","JPN":"喜んで受け入れます。","ENG":"Well, I have no reason to say no.","TWN":"我當然沒理由拒絕。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"마침 연기실력과는 상관없는 내사과에 자리가 비던 참이었고 말입니다.","JPN":"ちょうど演技力を必要としない内偵課で欠員が出ています。","ENG":"It just so happens that we have a billet in the Internal Investigation Department which doesn't require any acting skills.","TWN":"正好內務科有個職位不需要表演天賦，應該很適合他。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하하, 잘 됐군. 그럼 우리 훈련병을 잘 부탁하지.","JPN":"はは、それはよかった。では、うちの訓練兵をよろしく頼むぞ。","ENG":"Hah hah, that's perfect. Then I'll leave our trainee in your good hands.","TWN":"哈哈，太好了。那我們的訓練兵就交給妳了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};